	public void FMS_AGMT_MST() throws SQLException, IOException {
		
		function_nm = "FMS_AGMT_MST()";
		
		try {

			logger.checkpoint(fname, "\n<<START>>,<<FMS_AGMT_MST>>,,,", conn);
			logger.checkpoint1(fname1,function_nm+"E"+","+start_end_dt+",", conn);
			
			System.out.println("<<START>><<"+function_nm.substring(0, function_nm.length()-2)+">>");
			
			columns = "COMPANY_CD,COUNTERPARTY_CD,AGMT_TYPE,AGMT_NO,AGMT_REV,SIGNING_DT,START_DT,END_DT,RENEWAL_DT,AGMT_BASE,AGMT_TYP,STATUS,BUYER_NOM_CLAUSE,BUYER_NOM,BUYER_MONTH_NOM,BUYER_WEEK_NOM,BUYER_DAILY_NOM,SELLER_NOM_CLAUSE,SELLER_NOM,SELLER_MONTH_NOM,SELLER_WEEK_NOM,SELLER_DAILY_NOM,DAY_DEF,DAY_START_TIME,DAY_END_TIME,MDCQ,MDCQ_PERCENTAGE,MEASUREMENT,MEAS_STANDARD,MEAS_TEMPERATURE,PRESSURE_MIN_BAR,PRESSURE_MAX_BAR,OFF_SPEC_GAS,SPEC_GAS_ENERGY_BASE,SPEC_GAS_MIN_ENERGY,SPEC_GAS_MAX_ENERGY,ENT_BY,ENT_DT,MODIFY_DT,MODIFY_BY,FLAG,REV_DT,REMARKS,LIABILITY_CLAUSE,BILLING_CLAUSE,LC_CLAUSE,RENEWAL_FLAG,PRE_APPROVAL_DATE,PRE_APPROVAL,PRE_APPROVAL_BY,REOPEN_REQUEST_FLAG,REOPEN_REQUEST_DT,REOPEN_APPROVAL_FLAG,REOPEN_APPROVAL_DT,REOPEN_REQUEST_BY,REOPEN_APPROVE_BY,REMARK,CONT_NAME,AGMT_REF_NO,BILLING_FLAG,BUYER_FORNGT_NOM,SELLER_FORNGT_NOM,BUYER_NOM_CUTOFF,MEAS_CLAUSE,SPEC_CLAUSE,LIABILITY,TERMINATE_FLAG,TERMINATE_CLAUSE,TERMINATE_PLANED,TERMINATE_FORCE";

			workbook = new XSSFWorkbook();
			spreadsheet = workbook.createSheet("Sheet 1");

			nrow = 0;
			ncell = 0;
			count = 0;
			
			row = spreadsheet.createRow(nrow++);
			
			// Inserting Column Names
			for (int i = 0; i < columns.split(",").length; i++) {
				cell = row.createCell(i);
				cell.setCellValue(columns.split(",")[i]);
			}
			

			logger.checkpoint(fname, "COUNTERPARTY_ABBR,COUNTERPARTY_CD,AGMT_TYPE,AGMT_NO,AGMT_REV,TIMESTAMP,", conn);
			
			// Inserting Rest of the data
			queryString = "SELECT DISTINCT(A.COUNTERPARTY_ABBR), A.COUNTERPARTY_CD, A.EFF_DT  FROM FMS9_COUNTERPTY_MST A "
					+ "WHERE A.EFF_DT = (SELECT MAX(C.EFF_DT) FROM FMS9_COUNTERPTY_MST C WHERE A.COUNTERPARTY_CD = C.COUNTERPARTY_CD) "
					+ "AND A.COUNTERPARTY_ABBR != 'SEIPL' ORDER BY A.COUNTERPARTY_CD, A.EFF_DT DESC  ";
			stmt = conn.prepareStatement(queryString);
			rset = stmt.executeQuery();
			
			while (rset.next()) {
				
				queryString1 = "SELECT DISTINCT(B.CUSTOMER_CD), 'F', A.FGSA_NO, A.REV_NO, TO_CHAR(A.SIGNING_DT, 'DD/MM/YYYY hh24:mi:ss'), "
						+ "TO_CHAR(A.START_DT, 'DD/MM/YYYY hh24:mi:ss'), TO_CHAR(A.END_DT, 'DD/MM/YYYY hh24:mi:ss'), "
						+ "TO_CHAR(A.RENEWAL_DT, 'DD/MM/YYYY hh24:mi:ss'), A.FGSA_BASE, A.FGSA_TYPE, A.STATUS, A.BUYER_NOM_CLAUSE, A.BUYER_NOM, "
						+ "A.BUYER_MONTH_NOM, A.BUYER_WEEK_NOM, A.BUYER_DAILY_NOM, A.SELLER_NOM_CLAUSE, A.SELLER_NOM, A.SELLER_MONTH_NOM, "
						+ "A.SELLER_WEEK_NOM, A.SELLER_DAILY_NOM, A.DAY_DEF, A.DAY_START_TIME, A.DAY_END_TIME, A.MDCQ, A.MDCQ_PERCENTAGE, "
						+ "A.MEASUREMENT, A.MEAS_STANDARD, A.MEAS_TEMPERATURE, A.PRESSURE_MIN_BAR, A.PRESSURE_MAX_BAR, A.OFF_SPEC_GAS, A.SPEC_GAS_ENERGY_BASE, "
						+ "A.SPEC_GAS_MIN_ENERGY, A.SPEC_GAS_MAX_ENERGY, A.EMP_CD, TO_CHAR(A.ENT_DT, 'DD/MM/YYYY hh24:mi:ss'), NULL, NULL, "
						+ "A.FLAG, TO_CHAR(A.REV_DT, 'DD/MM/YYYY hh24:mi:ss'), A.REMARKS, A.LIABILITY_CLAUSE, A.BILLING_CLAUSE, A.LC_CLAUSE, "
						+ "A.RENEWAL_FLAG, TO_CHAR(A.PRE_APPROVAL_DATE, 'DD/MM/YYYY hh24:mi:ss'), A.PRE_APPROVAL, A.PRE_APPROVAL_BY, A.REOPEN_REQUEST_FLAG, "
						+ "TO_CHAR(A.REOPEN_REQUEST_DT, 'DD/MM/YYYY hh24:mi:ss'), A.REOPEN_APPROVAL_FLAG, TO_CHAR(A.REOPEN_APPROVAL_DT, 'DD/MM/YYYY hh24:mi:ss'), "
						+ "A.REOPEN_REQUEST_BY, A.REOPEN_APPROVE_BY, A.REMARK, 'SEIPL', 'S', 'Y', 'N', 'N', '00:00', NULL, NULL, 'Y', 'Y', NULL, 'Y', 'Y' "
						+ "FROM FMS7_FGSA_MST A, FMS7_CUSTOMER_MST B WHERE A.CUSTOMER_CD = B.CUSTOMER_CD AND B.COUNTERPARTY_CD = ? AND " 
						+ "B.EFF_DT = (SELECT MAX(C.EFF_DT) FROM FMS7_CUSTOMER_MST C WHERE C.CUSTOMER_CD = B.CUSTOMER_CD) "
						+ "AND (? IS NULL OR A.ENT_DT >= TO_DATE(?, 'DD/MM/YYYY HH24:MI:SS')) AND (? IS NULL OR A.ENT_DT <= TO_DATE(?, 'DD/MM/YYYY HH24:MI:SS'))";
				stmt1 = conn.prepareStatement(queryString1);
				stmt1.setString(1, rset.getString(2));
				stmt1.setString(2, delta_FromDt);
				stmt1.setString(3, delta_FromDt);
				stmt1.setString(4, delta_ToDt);
				stmt1.setString(5, delta_ToDt);

				rset1 = stmt1.executeQuery();
				
				while (rset1.next()) {
					
					row = spreadsheet.createRow(nrow++);
					ncell = 0;
					
					abbr = rset.getString(1);
					cd = rset.getString(2);
					agmt_no = rset1.getString(3);
					agmt_rev = rset1.getString(4);
					agmt_type = rset1.getString(2);
				
				    if (mpe.counterparty_map.containsKey(abbr)) {
				    	 abbr =mpe.counterparty_map.get(abbr); 
				    }
						
//					value = rset.getString(1) == null ? "null" : rset.getString(1);
					cell = row.createCell(ncell++);
					cell.setCellValue("'"+abbr+"'");
					
					for (int i = 1; i < columns.split(",").length; i++) {
						cell = row.createCell(ncell++);
						value = rset1.getString(i) == null ? "null" : rset1.getString(i);
						
						if (i == 9 && value.equals("O")) {	// FGSA_BASE
							value = "B";
							cell.setCellValue("'"+value+"'");
						}
						else if (i == 10) {	// FGSA_TYPE
							if (value.equals("T")) {
								value = "0";
							}
							else if (value.equals("S")) {
								value = "1";
							}
							cell.setCellValue("'"+value+"'");
						}
						else if (i == 11) {	// STATUS
							if (value.equals("Y")) {
								value = "A";
							}
							cell.setCellValue("'"+value+"'");
						}
						else if (i == 33 && !value.equals("null")) {	// SPEC_GAS_ENERGY_BASE
							if (value.equals("1  ")) {
								value = "GCV";
							}
							else if(value.equals("2  ")) {
								value = "NCV";
							}
							else {
								value = "0  ";
							}
							cell.setCellValue("'"+value+"'");
						}
						/*else if ((i == 36 || i == 49 || i == 54) && !value.equals("null")) {	// emp_abbr, PRE_APPROVAL_BY, REOPEN_REQUEST_BY
							value = getEmpAbbr(value);
							cell.setCellValue("'"+value+"'");
						}*/
						else if (i == 57) {	// CONT_NAME
							value = value+"-"+rset.getString(1)+"-F"+rset1.getString(3)+"-REV"+rset1.getString(4);
							cell.setCellValue("'"+value+"'");
						}
						else if (i == 58) {	// AGMT_REF_NO
							value = value+rset.getString(2)+"-"+rset1.getString(3);
							cell.setCellValue("'"+value+"'");
						}
						else if (i == 59) {	// BILLING_FLAG
							queryString2 = "SELECT CLAUSE_CD FROM FMS7_FGSA_CLAUSE_MST WHERE BUYER_CD = ? AND FGSA_NO = ? AND REV_NO = ? AND CLAUSE_CD = (SELECT CLAUSE_CD FROM FMS7_CLAUSE_MST WHERE CLAUSE_NM = 'Billing Details' )  AND FLAG = 'Y' ";
							stmt2 = conn.prepareStatement(queryString2);
							stmt2.setString(1, rset.getString(2));
							stmt2.setString(2, rset1.getString(3));
							stmt2.setString(3, rset1.getString(4));
							rset2 = stmt2.executeQuery();
							if (rset2.next()) {
								value = "Y";
							}
							else {
								value = "N";
							}
							rset2.close();
							stmt2.close();
							
							cell.setCellValue("'"+value+"'");
						}
						else if (i == 65) {	// LIABILITY
							queryString2 = "SELECT CLAUSE_CD FROM FMS7_FGSA_CLAUSE_MST WHERE BUYER_CD = ? AND FGSA_NO = ? AND REV_NO = ? AND CLAUSE_CD = (SELECT CLAUSE_CD FROM FMS7_CLAUSE_MST WHERE CLAUSE_NM = 'Liability' ) AND FLAG = 'Y'  ";
							stmt2 = conn.prepareStatement(queryString2);
							stmt2.setString(1, rset.getString(2));
							stmt2.setString(2, rset1.getString(3));
							stmt2.setString(3, rset1.getString(4));
							rset2 = stmt2.executeQuery();
							if (rset2.next()) {
								value = "Y";
							}
							else {
								value = "N";
							}
							rset2.close();
							stmt2.close();
							
							cell.setCellValue("'"+value+"'");
						}
						else if (i == 66) {	// TERMINATE_FLAG
							queryString2 = "SELECT CLAUSE_CD FROM FMS7_FGSA_CLAUSE_MST WHERE BUYER_CD = ? AND FGSA_NO = ? AND REV_NO = ? AND CLAUSE_CD = (SELECT CLAUSE_CD FROM FMS7_CLAUSE_MST WHERE CLAUSE_NM = 'Termination and Suspention' ) AND FLAG = 'Y' ";
							stmt2 = conn.prepareStatement(queryString2);
							stmt2.setString(1, rset.getString(2));
							stmt2.setString(2, rset1.getString(3));
							stmt2.setString(3, rset1.getString(4));
							rset2 = stmt2.executeQuery();
							if (rset2.next()) {
								value = "Y";
							}
							else {
								value = "N";
							}
							rset2.close();
							stmt2.close();
							
							cell.setCellValue("'"+value+"'");
						}
						else if (i == 68) {	// TERMINATE_PLANED
							queryString2 = "SELECT CLAUSE_CD FROM FMS7_FGSA_CLAUSE_MST WHERE BUYER_CD = ? AND FGSA_NO = ? AND REV_NO = ? AND CLAUSE_CD = (SELECT CLAUSE_CD FROM FMS7_CLAUSE_MST WHERE CLAUSE_NM = 'Planned Maintenance' ) AND FLAG = 'Y' ";
							stmt2 = conn.prepareStatement(queryString2);
							stmt2.setString(1, rset.getString(2));
							stmt2.setString(2, rset1.getString(3));
							stmt2.setString(3, rset1.getString(4));
							rset2 = stmt2.executeQuery();
							if (rset2.next()) {
								value = "Y";
							}
							else {
								value = "N";
							}
							rset2.close();
							stmt2.close();
							
							cell.setCellValue("'"+value+"'");
						}
						else if (i == 69) {	// TERMINATE_FORCE
							queryString2 = "SELECT CLAUSE_CD FROM FMS7_FGSA_CLAUSE_MST WHERE BUYER_CD = ? AND FGSA_NO = ? AND REV_NO = ? AND CLAUSE_CD = (SELECT CLAUSE_CD FROM FMS7_CLAUSE_MST WHERE CLAUSE_NM = 'Force Majeure' ) AND FLAG = 'Y' ";
							stmt2 = conn.prepareStatement(queryString2);
							stmt2.setString(1, rset.getString(2));
							stmt2.setString(2, rset1.getString(3));
							stmt2.setString(3, rset1.getString(4));
							rset2 = stmt2.executeQuery();
							if (rset2.next()) {
								value = "Y";
							}
							else {
								value = "N";
							}
							rset2.close();
							stmt2.close();
							
							cell.setCellValue("'"+value+"'");
						}
						else {
							cell.setCellValue("'"+value+"'");
						}
						
					}
					count++;
					logger.data(fname, (abbr + "," + cd + "," + agmt_type + "," + agmt_no + "," + agmt_rev + ","), conn, "");

				}
				rset1.close();
				stmt1.close();
			}
			stmt.close();
			rset.close();
			
			filename = migration_setup_dir + "EXPORT/FMS_AGMT_MST_"+start_end_dt+".xlsx";
			
			fileOut = new FileOutputStream(filename);  
			
			workbook.write(fileOut);
			fileOut.close(); 
			
			logger.checkpoint(fname, ("\nTOTAL DATA EXTRACTED :," + (count) + " ,,,"), conn);
			logger.checkpoint(fname, "<<END>>,<<FMS_AGMT_MST>>,,,", conn);
			

			logger.checkpoint1(fname1,count+",", conn);

			System.out.println("<<END>><<"+function_nm.substring(0, function_nm.length()-2)+">>");
			System.out.println();

			msg = "Data has been Extracted Successfully.";
			msg_type = "S";
			
		}
		catch (Exception e) {

			msg = "One of the Functions faced an Error. Extraction Terminated.";
			msg_type = "E";
			
			//LOGGER.log(Level.WARNING, "Error in Sales_SEIPL_Data_Extractor.java -> Sales_Excel_Extractor -> "+function_nm.substring(0, function_nm.length()-2)+"()  ", e);
			new SystemErrorLogger().InsertErrorLogger(db_src_file_name, function_nm, e);
			logger.error(fname, e, function_nm, conn, fname_error);
		}
		
	}
	
