public void FMS_LTCORA_CONT_TRANSPTR() throws SQLException, IOException {
	
	function_nm = "FMS_LTCORA_CONT_TRANSPTR()";
	
	try {

		System.out.println("<<START>><<"+function_nm.substring(0, function_nm.length()-2)+">>");
		logger.checkpoint(fname, "<<START>>,<<FMS_LTCORA_CONT_TRANSPTR>>,,,,", conn);
		
		logger.checkpoint1(fname1,function_nm+"E"+","+start_end_dt+",", conn);
		
		columns = "COMPANY_CD,COUNTERPARTY_CD,BUY_SALE,AGMT_NO,AGMT_REV,CONT_NO,CONT_REV,CONTRACT_TYPE,TRANSPORTER_CD,PLANT_SEQ_NO,ENT_BY,ENT_DT,AGMT_TYPE";

		workbook = new XSSFWorkbook();
		spreadsheet = workbook.createSheet("Sheet 1");

		nrow = 0;
		ncell = 0;
		count = 0;
		
		row = spreadsheet.createRow(nrow++);
		
		// Inserting Column Names
		for (int i = 0; i < columns.split(",").length; i++) {
			cell = row.createCell(i);
			cell.setCellValue(columns.split(",")[i]);
		}
		
		String trans_abbr = "", buy_sale= "",trans_cd="";
		int p_seqno = 0;

		logger.checkpoint(fname, "COUNTERPARTY_ABBR,BUY_SALE,AGMT_TYPE,AGMT_NO,AGMT_REV,TRANSPORTER_CD,PLANT_SEQ_NO,TIMESTAMP,", conn);
		
		// Inserting Rest of the data
		queryString = "SELECT DISTINCT(A.COUNTERPARTY_ABBR), A.COUNTERPARTY_CD, A.EFF_DT  FROM FMS9_COUNTERPTY_MST A "
				+ "WHERE A.EFF_DT = (SELECT MAX(C.EFF_DT) FROM FMS9_COUNTERPTY_MST C WHERE A.COUNTERPARTY_CD = C.COUNTERPARTY_CD) AND "
				+ "A.COUNTERPARTY_ABBR != 'SEIPL' ORDER BY A.COUNTERPARTY_CD, A.EFF_DT DESC  ";
		stmt = conn.prepareStatement(queryString);
		rset = stmt.executeQuery();
		
		while (rset.next()) {
			
			queryString1 = "SELECT DISTINCT(B.COUNTERPARTY_CD), 'C', A.AGREEMENT_NO , A.REV_NO ,A.CN_NO, A.CN_REV_NO , A.CN_TERM, C.TRANS_CD, NULL, C.ENT_BY, TO_CHAR(C.ENT_DT, 'DD/MM/YYYY hh24:mi:ss'), 'A' FROM "
					+ " FMS8_LNG_REGAS_MST A, FMS7_CUSTOMER_MST B, FMS8_LNG_REGAS_TRANS_DTL C  WHERE A.CUSTOMER_CD = B.CUSTOMER_CD AND A.MAPPING_ID = C.MAPPING_ID AND B.COUNTERPARTY_CD = ? "
					+ "AND B.EFF_DT = (SELECT MAX(C.EFF_DT) FROM FMS7_CUSTOMER_MST C WHERE B.CUSTOMER_CD = C.CUSTOMER_CD) "
					+ "AND (? IS NULL OR A.ENT_DT >= TO_DATE(?, 'DD/MM/YYYY HH24:MI:SS')) AND (? IS NULL OR A.ENT_DT <= TO_DATE(?, 'DD/MM/YYYY HH24:MI:SS')) AND A.LTCORA_CN_FLAG = 'C' ";
			stmt1 = conn.prepareStatement(queryString1);
			stmt1.setString(1, rset.getString(2));
			stmt1.setString(2, delta_FromDt);
			stmt1.setString(3, delta_FromDt);
			stmt1.setString(4, delta_ToDt);
			stmt1.setString(5, delta_ToDt);
			rset1 = stmt1.executeQuery();
			
			while (rset1.next()) {
				p_seqno = 1;
				trans_cd = rset1.getString(8);
				
				if(trans_cd.length()>2) {
				trans_cd = trans_cd.substring(0,trans_cd.length()-2);
				if(rset1.getString(8).length()>2)
				{
					p_seqno = Integer.parseInt(rset1.getString(8));
					p_seqno  = p_seqno % 100;
				}
				queryString2 = "SELECT A.TRANSPORTER_ABBR, B.SEQ_NO FROM FMS7_TRANSPORTER_MST A, FMS7_TRANSPORTER_PLANT_DTL B "
						+ "WHERE A.TRANSPORTER_CD = B.TRANSPORTER_CD AND A.TRANSPORTER_CD = ? AND B.SEQ_NO = ? AND (? IS NULL OR A.ENT_DT >= TO_DATE(?, 'DD/MM/YYYY HH24:MI:SS')) "
						+ "AND (? IS NULL OR A.ENT_DT <= TO_DATE(?, 'DD/MM/YYYY HH24:MI:SS')) ";
				stmt2 = conn.prepareStatement(queryString2);
				stmt2.setString(1, trans_cd);
				stmt2.setInt(2, p_seqno);
				stmt2.setString(3, delta_FromDt);
				stmt2.setString(4, delta_FromDt);
				stmt2.setString(5, delta_ToDt);
				stmt2.setString(6, delta_ToDt);
				rset2 = stmt2.executeQuery();
				
				while (rset2.next()) {
				
					abbr = rset.getString(1);
					cd = rset1.getString(1);
					buy_sale = rset1.getString(2);
					agmt_type = rset1.getString(12);
					agmt_no = rset1.getString(3);
					agmt_rev = rset1.getString(4);
					cont_type = rset1.getString(7);
					cont_no = rset1.getString(5);
					cont_rev = rset1.getString(6);
					trans_abbr = rset2.getString(1);
					p_seq_no = rset2.getString(2);
					row = spreadsheet.createRow(nrow++);
					ncell = 0;
					
					map=abbr+"-"+p_seq_no;
				
					if (mpe.counterparty_map.containsKey(abbr)) {
						abbr =mpe.counterparty_map.get(abbr); 
				    }
					cell = row.createCell(ncell++);
					cell.setCellValue("'"+abbr+"-"+agmt_rev+"'");
					
//					if(mpe.customer_map.containsKey(map))
//					{
//						p_seq_no=mpe.customer_map.get(map);
//					}
					
					for (int i = 1; i < columns.split(",").length; i++) {
						cell = row.createCell(ncell++);
						value = rset1.getString(i) == null ? "null" : rset1.getString(i);
						
						if(i == 1) {
							if(cont_type.equals("A")) {
								cont_ref = "A"+"-"+cd+"-"+agmt_no+"-"+cont_no+"-"+cont_rev;
								value = cont_ref;
							}
							else if(cont_type.equals("C")) {
								cont_ref = "C"+"-"+cd+"-"+agmt_no+"-"+cont_no+"-"+cont_rev;
								value = cont_ref;
							}
							cell.setCellValue("'"+value+"'");
						}
						else if (i == 7) {	// CONTRACT_TYP
							if (value.equals("A")) {
								cont_type = "Q";
								cell.setCellValue("'" + cont_type + "'");
							}
							else if(value.equals("C")) {
								cont_type = "O";
								cell.setCellValue("'" + cont_type + "'");
							}
						}
						else if (i == 8) {	// TRANSPORTER_ABBR
							
							if (mpe.transporter_map.containsKey(trans_abbr)) {
								trans_abbr = mpe.transporter_map.get(trans_abbr);
								
							}
							cell.setCellValue("'"+trans_abbr+"'");
						}
						else if (i == 9) {	// SEQ_NO-map
						
//							p_seq_no=p_seq_no.split("-")[0];
							cell.setCellValue("'"+p_seq_no+"'");
						
						}
						else {
							cell.setCellValue("'"+value+"'");
						}
					}
					
					count++;
					logger.data(fname, (abbr + "," + buy_sale + ","+ agmt_type + "," + agmt_no + "," + agmt_rev + "," + cont_type + "," + cont_no + "," + cont_rev + "," + trans_abbr + "," + p_seq_no + ","), conn, "");
				}
				rset2.close();
				stmt2.close();
			
			}
				else {
					
				queryString2 = "SELECT TRANSPORTER_ABBR FROM FMS7_TRANSPORTER_MST "
						+ "WHERE TRANSPORTER_CD = ? AND (? IS NULL OR ENT_DT >= TO_DATE(?, 'DD/MM/YYYY HH24:MI:SS')) "
						+ "AND (? IS NULL OR ENT_DT <= TO_DATE(?, 'DD/MM/YYYY HH24:MI:SS')) ";
				stmt2 = conn.prepareStatement(queryString2);
				stmt2.setString(1, trans_cd);
				stmt2.setString(2, delta_FromDt);
				stmt2.setString(3, delta_FromDt);
				stmt2.setString(4, delta_ToDt);
				stmt2.setString(5, delta_ToDt);
				rset2 = stmt2.executeQuery();
				
				while (rset2.next()) {
				
					abbr = rset.getString(1);
					cd = rset1.getString(1);
					buy_sale = rset1.getString(2);
					agmt_type = rset1.getString(12);
					agmt_no = rset1.getString(3);
					agmt_rev = rset1.getString(4);
					cont_type = rset1.getString(7);
					cont_no = rset1.getString(5);
					cont_rev = rset1.getString(6);
					trans_abbr = rset2.getString(1);
					row = spreadsheet.createRow(nrow++);
					ncell = 0;
					
//					map=abbr+"-"+p_seq_no;
				
					if (mpe.counterparty_map.containsKey(abbr)) {
						abbr =mpe.counterparty_map.get(abbr); 
				    }
					
					if(mpe.transporter_map.containsKey(trans_abbr))
					{
						trans_abbr=mpe.transporter_map.get(trans_abbr);
					}
					cell = row.createCell(ncell++);
					cell.setCellValue("'"+abbr+"-"+agmt_rev+"'");
					
					if(mpe.meter_map.containsKey(rset2.getString(1)))
					{
						plant_abbr=mpe.meter_map.get(rset2.getString(1));
					}
					
					for (int i = 1; i < columns.split(",").length; i++) {
						cell = row.createCell(ncell++);
						value = rset1.getString(i) == null ? "null" : rset1.getString(i);
						
						if(i == 1) {
							if(cont_type.equals("A")) {
								cont_ref = "A"+"-"+cd+"-"+agmt_no+"-"+cont_no+"-"+cont_rev;
								value = cont_ref;
							}
							else if(cont_type.equals("C")) {
								cont_ref = "C"+"-"+cd+"-"+agmt_no+"-"+cont_no+"-"+cont_rev;
								value = cont_ref;
							}
							cell.setCellValue("'"+value+"'");
						}
						else if (i == 7) {	// CONTRACT_TYP
							if (value.equals("A")) {
								cont_type = "Q";
								cell.setCellValue("'" + cont_type + "'");
							}
							else if(value.equals("C")) {
								cont_type = "O";
								cell.setCellValue("'" + cont_type + "'");
							}
						}
						else if (i == 8) {	// TRANSPORTER_ABBR
							
							cell.setCellValue("'"+trans_abbr+"'");
						}
						else if (i == 9) {	// SEQ_NO-map
						
							queryString2 = "SELECT SEQ_NO FROM FMS7_TRANSPORTER_PLANT_DTL WHERE PLANT_SHORT_ABBR = ? ";
							stmt2 = conn.prepareStatement(queryString2);
							stmt2.setString(1, plant_abbr);
							rset2 = stmt2.executeQuery();
							if (rset2.next()) {									
								p_seq_no = rset2.getString(1);
							}
							else {
								p_seq_no = "1";
							}
							cell.setCellValue("'"+p_seq_no+"'");
						}
						else {
							cell.setCellValue("'"+value+"'");
						}
					}
					
					count++;
					logger.data(fname, (abbr + "," + buy_sale + ","+ agmt_type + "," + agmt_no + "," + agmt_rev + "," + cont_type + "," + cont_no + "," + cont_rev + "," + trans_abbr + "," + p_seq_no + ","), conn, "");
				}
				rset2.close();
				stmt2.close();
				}
			}
			rset1.close();
			stmt1.close();
			
			//RE-GAS
			queryString1 = "SELECT DISTINCT(A.CUSTOMER_CD), 'C', '1' , '0' , C.RE_GAS_NO, C.REV_NO , 'Q', C.TRANSPORTER_CD, NULL, C.EMP_CD, TO_CHAR(C.ENT_DT, 'DD/MM/YYYY hh24:mi:ss'), 'A' FROM "
					+ " FMS7_RE_GAS_MST A, FMS7_CUSTOMER_MST B, FMS7_RE_GAS_TRANSPORTER_MST C  WHERE A.CUSTOMER_CD = B.CUSTOMER_CD AND A.CUSTOMER_CD = C.CUSTOMER_CD AND A.RE_GAS_NO = C.RE_GAS_NO AND B.COUNTERPARTY_CD = ? "
					+ "AND B.EFF_DT = (SELECT MAX(C.EFF_DT) FROM FMS7_CUSTOMER_MST C WHERE B.CUSTOMER_CD = C.CUSTOMER_CD) "
					+ "AND (? IS NULL OR C.ENT_DT >= TO_DATE(?, 'DD/MM/YYYY HH24:MI:SS')) AND (? IS NULL OR C.ENT_DT <= TO_DATE(?, 'DD/MM/YYYY HH24:MI:SS')) ";
			stmt1 = conn.prepareStatement(queryString1);
			stmt1.setString(1, rset.getString(2));
			stmt1.setString(2, delta_FromDt);
			stmt1.setString(3, delta_FromDt);
			stmt1.setString(4, delta_ToDt);
			stmt1.setString(5, delta_ToDt);
			rset1 = stmt1.executeQuery();
			
			while (rset1.next()) {
				p_seqno = 1;
				trans_cd = rset1.getString(8);
				queryString2 = "SELECT TRANSPORTER_ABBR FROM FMS7_TRANSPORTER_MST "
						+ "WHERE TRANSPORTER_CD = ? AND (? IS NULL OR ENT_DT >= TO_DATE(?, 'DD/MM/YYYY HH24:MI:SS')) "
						+ "AND (? IS NULL OR ENT_DT <= TO_DATE(?, 'DD/MM/YYYY HH24:MI:SS')) ";
				stmt2 = conn.prepareStatement(queryString2);
				stmt2.setString(1, trans_cd);
				stmt2.setString(2, delta_FromDt);
				stmt2.setString(3, delta_FromDt);
				stmt2.setString(4, delta_ToDt);
				stmt2.setString(5, delta_ToDt);
				rset2 = stmt2.executeQuery();
				
				while (rset2.next()) {
				
					abbr = rset.getString(1);
					cd = rset1.getString(1);
					buy_sale = rset1.getString(2);
					agmt_type = rset1.getString(12);
					agmt_no = rset1.getString(3);
					agmt_rev = rset1.getString(4);
					cont_type = rset1.getString(7);
					cont_no = rset1.getString(5);
					cont_rev = rset1.getString(6);
					trans_abbr = rset2.getString(1);
					row = spreadsheet.createRow(nrow++);
					ncell = 0;
					
//					map=abbr+"-"+p_seq_no;
				
					if (mpe.counterparty_map.containsKey(abbr)) {
						abbr =mpe.counterparty_map.get(abbr); 
				    }
					
					if(mpe.transporter_map.containsKey(trans_abbr))
					{
						trans_abbr=mpe.transporter_map.get(trans_abbr);
					}
					cell = row.createCell(ncell++);
					cell.setCellValue("'"+abbr+"-"+agmt_rev+"'");
					
					if(mpe.meter_map.containsKey(rset2.getString(1)))
					{
						plant_abbr=mpe.meter_map.get(rset2.getString(1));
					}
					
					for (int i = 1; i < columns.split(",").length; i++) {
						cell = row.createCell(ncell++);
						value = rset1.getString(i) == null ? "null" : rset1.getString(i);
						
						
						if(i == 1) {
							cont_ref = "R"+"-"+cd+"-"+cont_no;
							value = cont_ref;
							cell.setCellValue("'"+value+"'");
						}
						else if (i == 8) {	// TRANSPORTER_ABBR
							
							cell.setCellValue("'"+trans_abbr+"'");
						}
						else if (i == 9) {	// SEQ_NO-map
						
							queryString2 = "SELECT SEQ_NO FROM FMS7_TRANSPORTER_PLANT_DTL WHERE PLANT_SHORT_ABBR = ? ";
							stmt2 = conn.prepareStatement(queryString2);
							stmt2.setString(1, plant_abbr);
							rset2 = stmt2.executeQuery();
							if (rset2.next()) {									
								p_seq_no = rset2.getString(1);
							}
							else {
								p_seq_no = "1";
							}
							cell.setCellValue("'"+p_seq_no+"'");
						}
						else {
							cell.setCellValue("'"+value+"'");
						}
					}
					
					count++;
					logger.data(fname, (abbr + "," + buy_sale + ","+ agmt_type + "," + agmt_no + "," + agmt_rev + "," + cont_type + "," + cont_no + "," + cont_rev + "," + trans_abbr + "," + p_seq_no + ","), conn, "");
				}
				rset2.close();
				stmt2.close();
			}
			rset1.close();
			stmt1.close();
		}
		stmt.close();
		rset.close();
		
		filename = migration_setup_dir + "EXPORT/FMS_LTCORA_CONT_TRANSPTR_"+start_end_dt+".xlsx";
		
		fileOut = new FileOutputStream(filename);  
		
		workbook.write(fileOut);
		fileOut.close(); 

		System.out.println("<<END>><<"+function_nm.substring(0, function_nm.length()-2)+">>");
		System.out.println();
		
		logger.checkpoint(fname, ("\nTOTAL DATA EXTRACTED :," + count + ", "), conn);
		logger.checkpoint(fname, "<<END>>,<<FMS_LTCORA_CONT_TRANSPTR>>,,,,", conn);

		logger.checkpoint1(fname1,count+",", conn);

		msg = "Data has been Extracted Successfully.";
		msg_type = "S";
		
	}
	catch (Exception e) {

		msg = "One of the Functions faced an Error. Extraction Terminated.";
		msg_type = "E";
		
		//LOGGER.log(Level.WARNING, "Error in Sales_SEIPL_Data_Extractor.java -> Sales_Excel_Extractor -> "+function_nm.substring(0, function_nm.length()-2)+"  ", e);
		new SystemErrorLogger().InsertErrorLogger(db_src_file_name, function_nm, e);
		logger.error(fname, e, function_nm, conn, fname_error);
	}
	
}

