public void FMS_INV_ADV_DTL_UPDATE() throws SQLException, IOException {
	
	function_nm = "FMS_INV_ADV_DTL_UPDATE()";
	
	try {
		
		System.out.println("<<START>><<"+function_nm.substring(0, function_nm.length()-2)+">>");
		logger.checkpoint(fname, "<<START>>,<<FMS_INV_ADV_DTL_UPDATE>>,,,,", conn);
		
		logger.checkpoint1(fname1,function_nm+"E"+","+start_end_dt+",", conn);
		
		columns = "COMPANY_CD,BU_STATE_TIN,INVOICE_SEQ,FINANCIAL_YEAR,SEC_INT_REF,INV_COMPONENT,AMOUNT,ENT_BY,ENT_DT,MODIFY_BY,MODIFY_DT,"
				+ "TAX_AMT,TAX_STRUCT_CD,TDS_STRUCT_CD,TDS_TAX_AMT,BU_UNIT,PLANT_SEQ,GROSS_AMT";
		count = 0;
		
		String inv_seq= "", comp="",taxAmount="",plant_seq="",tds_amt="",tax_amt="",tax_cd="",bu_seq="";
		
		String fname_csv = "", str = "", taxField="",new_inv="",adv_no="";
		
		
		fname_csv = migration_setup_dir + "EXPORT/FMS_INV_ADV_DTL_UPDATE_" + start_end_dt + ".csv";
		
		FileWriter fw = new FileWriter(fname_csv, false); 
		fw.close();
		
		// Inserting Column Names
		for (int i = 0; i < columns.split(",").length; i++) {
			str += columns.split(",")[i] + ",";
		}
		logger.insert_data(fname_csv, str, conn);
		
		logger.checkpoint(fname, "COMPANY_CD,BU_STATE_TIN,INVOICE_SEQ,FINANCIAL_YEAR,PDF_TYPE,INVOICE_TYPE,TIMESTAMP,", conn);
		
		queryString = "SELECT DISTINCT(A.CUSTOMER_CD), A.EFF_DT, A.CUSTOMER_ABBR  FROM FMS7_CUSTOMER_MST A "
				+ "WHERE A.EFF_DT = (SELECT MAX(C.EFF_DT) FROM FMS7_CUSTOMER_MST C WHERE A.CUSTOMER_CD = C.CUSTOMER_CD) "
				+ "ORDER BY A.CUSTOMER_CD, A.EFF_DT DESC  ";
		stmt = conn.prepareStatement(queryString);
		rset = stmt.executeQuery();
		while(rset.next())
		{
			cd=rset.getString(1);
			
			queryString2 = "SELECT CONTRACT_TYPE, HLPL_INV_SEQ_NO, FINANCIAL_YEAR, "
					+ "NEW_INV_SEQ_NO, MAPPING_ID, ADV_INV_NO,TAX_AMT_INR, TAX_STRUCT_CD, TDS_PERCENT, SUP_PLANT_CD+1, GROSS_AMT_INR, PLANT_SEQ_NO, TO_CHAR(INVOICE_DT, 'DD/MM/YYYY HH24:MI:SS') "
					+ "FROM FMS7_INVOICE_MST WHERE CUSTOMER_CD = ? AND CONTRACT_TYPE IN ('C','B') AND PAY_TYPE IN ('AP','SP') ";
				stmt2 = conn.prepareStatement(queryString2);
				stmt2.setString(1, cd);
				rset2 = stmt2.executeQuery();
				
			while(rset2.next()) 
			{
				inv_seq = rset2.getString(2);
				fin_yr = rset2.getString(3);
				new_inv = rset2.getString(4);
				map_id = rset2.getString(5);
				adv_no = rset2.getString(6);
				abbr = rset.getString(3);
				double tds_per,gross_amt;
				tax_amt = rset2.getString(7);
				tax_cd = rset2.getString(8);
//				tds_amt = rset2.getString(9);
				tds_per = rset2.getDouble(9);
				bu_seq = rset2.getString(10);
				plant_seq = rset2.getString(12);
				gross_amt = rset2.getDouble(11);
				BigDecimal tdsAmtBD;
				
				
				queryString4="SELECT REMARK FROM FMS7_TAX_STRUCTURE WHERE TAX_STR_CD = ? AND APP_DATE <= TO_DATE(?, 'DD/MM/YYYY HH24:MI:SS') ORDER BY APP_DATE DESC";
				stmt4 = conn.prepareStatement(queryString4);
				stmt4.setString(1, tax_cd);
				stmt4.setString(2, rset2.getString(13));
				rset4 = stmt4.executeQuery();
				
				   if(rset4.next()) {	
					   tax_cd = rset4.getString(1);
					   tax_cd = tax_cd.replaceAll(",", "@ ");
					   tax_cd = tax_cd.replaceAll("\n", " ");
					   tax_cd = tax_cd.replaceAll("\r", " ");
					   tax_cd = tax_cd.replaceAll("\"", " ");
					   if (tax_cd.contains("MH")) {
						   tax_cd = tax_cd.split(" MH")[0] + "%";
						}
						else if (tax_cd.contains("AP")) {
							tax_cd = tax_cd.split(" AP")[0] + "%";
						}
						else if (tax_cd.contains("ADD. VAT")) {
							tax_cd = tax_cd.replace("ADD. VAT", "ADVAT");
						}
						else if (tax_cd.contains("STAX 0%")) {
							tax_cd = tax_cd.replace("STAX 0%", "ZSTAX 0%");
						}
				   }else {
					   tax_cd = null; 
				   }							   								  
				   stmt4.close();
				   rset4.close();
				  
				   str += tax_cd + ",";
			
				
				queryString1 = "SELECT '2', NULL , A.HLPL_INV_SEQ_NO, A.FINANCIAL_YEAR, A.ADV_INV_NO, A.TAX_ADJ_REMARK, A.ADJUST_AMT, A.ENTER_BY, "
						+ " TO_CHAR(A.ENTER_DT, 'DD/MM/YYYY HH24:MI:SS'), NULL, NULL, B.AGREEMENT_NO, B.REV_NO, B.CN_NO, B.CN_REV_NO, B.CN_TERM, B.CUSTOMER_CD, NULL, NULL  "
						+ " FROM FMS8_ADV_INV_DTL A, FMS8_LNG_REGAS_MST B  "
						+ " WHERE A.MAPPING_ID = B.MAPPING_ID AND A.HLPL_INV_SEQ_NO = ? AND A.FINANCIAL_YEAR = ? AND A.MAPPING_ID = ? AND A.CONTRACT_TYPE IN ('C','B') " ;
//						+ " AND RECEIPT_VOU_NO = ? ";
						
				stmt1 = conn.prepareStatement(queryString1);
				stmt1.setString(1,inv_seq);
				stmt1.setString(2,fin_yr);
//				stmt1.setString(3,new_inv);
				stmt1.setString(3,map_id);
//				stmt1.setString(4,new_inv);
				rset1 = stmt1.executeQuery();
				
				while(rset1.next())
				{	
					taxField=rset1.getString(6);
					
					if(taxField!=null) {
					if (mpe.counterparty_map.containsKey(abbr)) {
						abbr =mpe.counterparty_map.get(abbr); 
					}
					
					cont_type = rset1.getString(16);
					agmt_no = rset1.getString(12);
					agmt_rev = rset1.getString(13);
					cont_no = rset1.getString(14);
					cont_rev = rset1.getString(15);
					customer_cd = rset1.getString(17);
					
//					System.out.println(inv_seq+"="+fin_yr+"="+map_id+"="+rset1.getString(5));
					
					
					for (int j = 0; j <= taxField.split(",").length; j++) {
						str = "";
						str += fin_yr + ",";
						for (int i = 1; i < columns.split(",").length; i++) {
							
						 if (i == 1) {	
							value = new_inv;
							str += value + ",";
						 }
						 else if(i == 4) {
							 value = rset1.getString(5);
							 str += value + ",";
						 }
						 else if(i == 5) {
							 
							 if(j == 0 && rset1.getString(7)!=null) {
								 comp = "GROSS";
								 str += comp + ",";
							 }
							 else if(rset1.getString(6)!=null) {
								
//								 String[] taxParts = taxField.split(",");
								 String tax_code = taxField.split(",")[j-1].split("@")[0];
								 taxAmount = taxField.split(",")[j-1].split("@")[1];
								 
								 queryString4 = "SELECT COMPO_ABR FROM FMS7_COMPO_MST WHERE COMPO_CD = ? ";
									stmt4 = conn.prepareStatement(queryString4);
									stmt4.setString(1, tax_code);
									rset4 = stmt4.executeQuery();
									
									if(rset4.next()) {
										comp = rset4.getString(1);
									}
									else {
										comp = "";
									}
									stmt4.close();
									rset4.close();
								 
								 str += comp + ",";
							 }
						 }
						 else if(i == 6) {
							 if(comp.equals("GROSS")) {
								 str += rset1.getString(7) + ",";
							 }
							 else {
								 str += taxAmount + ",";
							 }
						 }
						 else if(i == 9) {
							 if(tax_cd.contains("CGST") && tax_cd.contains("SGST")) {
								 value = (Integer.parseInt(tax_cd.split("%")[0].split(" ")[1]) * 2) + "";
							 }
							 else if (tax_cd.contains("IGST")) {
								 value = tax_cd.split("%")[0].split(" ")[1];
							 }
							 str += value + ",";
						 }
						 else if(i == 11) {
							 str += tax_amt + ",";
						 }
						 else if(i == 12) {
							 str += tax_cd + ",";
						 }
						 else if(i == 13) {
						 	queryString4 = "SELECT TDS_PERCENT FROM FMS7_INVOICE_MST WHERE NEW_INV_SEQ_NO = ? ";
							stmt4 = conn.prepareStatement(queryString4);
							stmt4.setString(1, rset1.getString(5));
							rset4 = stmt4.executeQuery();
							
							if(rset4.next()) {
								tds_per = rset4.getDouble(1);
							}
							else {
								tds_per = 0;
							}
							stmt4.close();
							rset4.close();
							str += "TDS "+tds_per+"%" + ",";
						 }
						 else if(i == 14) {
								
								BigDecimal tdsPerBD = BigDecimal.valueOf(tds_per);
								BigDecimal grossAmtBD = BigDecimal.valueOf(gross_amt);
								
								if(rset2.getString(9)!=null) {
									 tdsAmtBD = grossAmtBD.multiply(tdsPerBD).divide(BigDecimal.valueOf(100));
								}else {
									 tdsAmtBD = null;
								}
								str += tdsAmtBD + ",";
						 }
						 else if(i == 15) {
							 str += bu_seq + ",";
						 }
						 else if(i == 16) {
							 str += plant_seq + ",";
						 }
						 else if(i == 17) {
							 
							 String gross_amt_inr = rset2.getString(11);
							 str += gross_amt_inr + ",";
						 }
//						 else if(i == 18) {
//							 
//							 if(cont_type.equals("A")) {
//									cont_ref = "A"+"-"+customer_cd+"-"+agmt_no+"-"+cont_no+"-"+cont_rev;
//									value = cont_ref;
//								}
//								else if(cont_type.equals("C")) {
//									cont_ref = "C"+"-"+customer_cd+"-"+agmt_no+"-"+cont_no+"-"+cont_rev;
//									value = cont_ref;
//								}
//								str += value + ",";
//						 }
						else {
								value = rset1.getString(i+1) == null ? "null" : rset1.getString(i+1).replaceAll(",", " ");
								str += value + ",";
						}
							
						}
						logger.insert_data(fname_csv, str, conn);
						count++;
						logger.data(fname, (company_cd+",24" + ","+inv_seq+ "," +fin_yr+","), conn, "");
					}
				}
					
				}					
				stmt1.close();
				rset1.close();
			}
			rset2.close();
			stmt2.close();
			}
		rset.close();
		stmt.close();
		
		logger.checkpoint(fname, ("\nTOTAL DATA EXTRACTED :," + count + ",,,,"), conn);
		logger.checkpoint(fname, "<<END>>,<<FMS_INV_ADV_DTL_UPDATE>>,,,,", conn);
		
		logger.checkpoint1(fname1,count+",", conn);
		
		System.out.println("<<END>><<"+function_nm.substring(0, function_nm.length()-2)+">>");
		System.out.println();
		
		msg = "Data has been Extracted Successfully.";
		msg_type = "S";
	}
	catch (Exception e) {
		
		msg = "One of the Functions faced an Error. Extraction Terminated.";
		msg_type = "E";
		
		//LOGGER.log(Level.WARNING, "Error in Sales_SEIPL_Data_Extractor.java -> Sales_Excel_Extractor -> "+function_nm.substring(0, function_nm.length()-2)+"()  ", e);
		new SystemErrorLogger().InsertErrorLogger(db_src_file_name, function_nm, e);
	}
	
}
	
